import React from "react";

export default function Pagination({ page, setPage, filteredLength, pageSize }) {
  if (filteredLength <= pageSize) return null;

  const totalPages = Math.ceil(filteredLength / pageSize);

  return (
    <div style={{
      textAlign: "center",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      gap: "12px",
      margin: "16px 0",
      color: "white",
      fontSize: "14px",
      fontFamily: "'Montserrat', sans-serif",
    }}>
      <button
        onClick={() => setPage(p => p - 1)}
        disabled={page === 1}
        style={{
          background: "rgba(255,255,255,0.15)",
          border: "1px solid rgba(255,255,255,0.3)",
          color: "white",
          borderRadius: "8px",
          padding: "6px 14px",
          cursor: page === 1 ? "default" : "pointer",
          opacity: page === 1 ? 0.4 : 1,
          fontSize: "16px",
          transition: "all 0.2s ease",
        }}
      >
        ←
      </button>

      <span style={{ fontStyle: "italic" }}>
        {page} / {totalPages}
      </span>

      <button
        onClick={() => setPage(p => p + 1)}
        disabled={page * pageSize >= filteredLength}
        style={{
          background: "rgba(255,255,255,0.15)",
          border: "1px solid rgba(255,255,255,0.3)",
          color: "white",
          borderRadius: "8px",
          padding: "6px 14px",
          cursor: page * pageSize >= filteredLength ? "default" : "pointer",
          opacity: page * pageSize >= filteredLength ? 0.4 : 1,
          fontSize: "16px",
          transition: "all 0.2s ease",
        }}
      >
        →
      </button>
    </div>
  );
}
